ed=yes server=162.159.200.1,162.159.200.123\n    } on-error={ :put \"skip/gagal command: /system ntp client set enabled=yes server=162.159.200.1,162.159.200.123\" }\n\n    # --- Script/export block: /ip hotspot profile ---\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId use-radius=yes radius-accounting=yes } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] use-radius=yes radius-accounting=yes\" }\n    }\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId radius-interim-update=0s } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] radius-interim-update=0s\" }\n    }\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId install-hotspot-queue=no } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] install-hotspot-queue=no\" }\n    }\n\n    # --- /radius comment=Radius Billing Direct ---\n    :foreach rbillId in=[/radius find where comment=\"Radius Billing Direct\"] do={\n        :do {\n            /radius remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=Radius Billing Direct\" }\n    }\n    :do {\n        /radius add service=ppp,hotspot called-id=\"\" domain=\"\" address=\"#server_ip#\" secret=\"#secret#\" authentication-port=\"#auth_port#\" accounting-port=\"#acct_port#\" timeout=300ms accounting-backup=no realm=\"\" protocol=udp certificate=none require-message-auth=no comment=\"Radius Billing Direct\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=Radius Billing Direct\" }\n\n    :put \"RBILL convert selesai.\"\n} on-error={ :put \"RBILL convert error. Cek command terakhir/parameter beda versi.\" }','#server_ip#,#nasname#,#secret#,#auth_port#,#acct_port#','Script RADIUS langsung via IP Publik MikroTik, cocok untuk koneksi direct tanpa VPN','2026-05-30 21:22:43','2026-05-31 00:03:49'),(2,'PPPOE ONLY','v7','