INSERT INTO `voucher_templates` VALUES (1,'standar','<div style=\"\n  display:inline-block;\n  vertical-align:top;\n  width:293px;\n  box-sizing:border-box;\n  border:2px solid #777;\n  margin:3px;\n  padding:0;\n  background:#fff;\n  overflow:hidden;\n\">\n\n<table style=\"\n  width:100%;\n  border-collapse:collapse;\n  table-layout:fixed;\n  margin:0;\n  padding:0;\n  font-family:Tahoma, Arial, sans-serif;\n  color:#000;\n  background:#fff;\n\">\n\n  <thead>\n    <tr>\n      <td style=\"\n        width:50%;\n        padding:5px 4px 2px 6px;\n        vertical-align:top;\n        box-sizing:border-box;\n      \">\n        <img src=\"#logo#\" width=\"100\" height=\"30\" style=\"display:block;margin:0;\">\n      </td>\n\n      <td style=\"\n        width:50%;\n        padding:4px 6px 2px 4px;\n        text-align:right;\n        vertical-align:top;\n        box-sizing:border-box;\n      \">\n        <div style=\"\n          font-weight:bold;\n          font-size:15px;\n          color:#000;\n          line-height:16px;\n        \">\n          <span style=\"\n            font-size:10px;\n            position:relative;\n            top:-4px;\n          \">Rp</span> #harga#\n        </div>\n\n        <div style=\"\n          font-weight:bold;\n          font-size:10px;\n          color:#000;\n          line-height:13px;\n          margin-top:1px;\n        \">\n          #aktif#\n        </div>\n      </td>\n    </tr>\n  </thead>\n\n  <tbody>\n\n    <tr>\n      <td colspan=\"2\" style=\"\n        text-align:center;\n        font-weight:bold;\n        font-size:12px;\n        padding:3px 4px 1px 4px;\n        line-height:14px;\n        box-sizing:border-box;\n      \">\n        Voucher harap disimpan sampai masa berlaku habis\n      </td>\n    </tr>\n\n    <tr>\n      <td colspan=\"2\" style=\"\n        text-align:center;\n        padding:4px 3px 5px 3px;\n        box-sizing:border-box;\n      \">\n        <div style=\"\n          display:inline-block;\n          width:auto;\n          min-width:100px;\n          max-width:246px;\n          box-sizing:border-box;\n          padding:4px 12px;\n          border:2px solid #000;\n          border-radius:18px;\n          background:#fff;\n          text-align:center;\n        \">\n          <span style=\"\n             display:block;\n  font-family:Consolas, Courier New, monospace;\n  font-size:30px;\n  font-weight:bold;\n  letter-spacing:1.3px;\n  color:#000;\n  line-height:32px;\n  text-align:center;\n  white-space:nowrap;\n          \">\n            #username#\n          </span>\n        </div>\n      </td>\n    </tr>\n\n    <tr>\n      <td style=\"\n        width:50%;\n        text-align:left;\n        font-weight:bold;\n        font-size:11px;\n        padding:2px 2px 2px 6px;\n        line-height:13px;\n        box-sizing:border-box;\n      \">\n        #dns#\n      </td>\n\n      <td style=\"\n        width:50%;\n        text-align:right;\n        font-weight:bold;\n        font-size:11px;\n        padding:2px 6px 2px 2px;\n        line-height:13px;\n        box-sizing:border-box;\n      \">\n        #kode#\n      </td>\n    </tr>\n\n    <tr>\n      <td style=\"\n        width:50%;\n        text-align:left;\n        font-weight:bold;\n        font-size:11px;\n        padding:2px 2px 2px 6px;\n        line-height:13px;\n        box-sizing:border-box;\n      \">\n        Outlet : #outlet#\n      </td>\n\n      <td style=\"\n        width:50%;\n        text-align:right;\n        font-weight:bold;\n        font-size:11px;\n        padding:2px 6px 2px 2px;\n        line-height:13px;\n        box-sizing:border-box;\n      \">\n        #nomor#\n      </td>\n    </tr>\n\n    <tr>\n      <td colspan=\"2\" style=\"\n        text-align:center;\n        font-weight:bold;\n        font-size:13px;\n        padding:3px 4px 4px 4px;\n        line-height:14px;\n        border-top:1px dashed #000;\n        box-sizing:border-box;\n      \">\n        Powered by PT Remala Abadi\n      </td>\n    </tr>\n